// ─── Date Logic ───────────────────────────────────────────────────────────────
const now = new Date();
const dayOfWeek = now.getDay(); // 0=Sun, 1=Mon, 2=Tue, 3=Wed, 4=Thu, 5=Fri, 6=Sat

// Determine which day key to use
const DAY_MAP = { 1: "monday", 3: "wednesday", 5: "friday" };
const dayKey = DAY_MAP[dayOfWeek];

if (!dayKey) {
  throw new Error(`Today (dayOfWeek=${dayOfWeek}) is not a publishing day. This workflow runs Mon/Wed/Fri only.`);
}

// Week-of-month cycling (1-indexed, loops every 4 weeks)
// Anchor: first Monday on or after 2025-01-06 (ISO week 2)
const EPOCH = new Date("2025-01-06T00:00:00Z"); // known week1 Monday
const msPerWeek = 7 * 24 * 60 * 60 * 1000;
const weeksSinceEpoch = Math.floor((now - EPOCH) / msPerWeek);
const weekIndex = ((weeksSinceEpoch % 4) + 4) % 4; // 0-3
const WEEK_KEYS = ["week1", "week2", "week3", "week4"];
const weekKey = WEEK_KEYS[weekIndex];

// ─── Script Selection ────────────────────────────────────────────────────────
const script = SCRIPTS[weekKey][dayKey];
const format = FORMATS[script.format];

// ─── Full Script Text (for teleprompter / caption burn-in) ────────────────────
const fullScriptText = `${script.hook}\n\n${script.body}\n\n${script.cta}`;

// ─── Production Brief ─────────────────────────────────────────────────────────
const productionDate = now.toISOString().split("T")[0];
const productionBrief = `
==========================================================
FRATERIT CONTENT PRODUCTION BRIEF
${productionDate} | ${weekKey.toUpperCase()} — ${dayKey.toUpperCase()}
==========================================================

FORMAT:     ${format.label}
STRUCTURE:  ${format.structure}
VOICE TONE: ${METADATA.voice_tone}
VIDEO SPEC: ${METADATA.video_format}

----------------------------------------------------------
TITLE:      ${script.title}
----------------------------------------------------------

HOOK:
${script.hook}

BODY:
${script.body}

CTA:
${script.cta}

----------------------------------------------------------
YOUTUBE METADATA
----------------------------------------------------------
Title:       ${script.youtube_title}
Description: ${script.youtube_description}
Tags:        ${script.youtube_tags.join(", ")}

----------------------------------------------------------
B-ROLL / STOCK FOOTAGE KEYWORDS
----------------------------------------------------------
${format.pexels_keywords.join(", ")}

----------------------------------------------------------
PRODUCTION NOTES
----------------------------------------------------------
• Vertical 9:16 format — shoot or crop accordingly
• 30 seconds target length
• Captions must be burned in before publishing
• Lead with hook in first 2 seconds — no intro, no logo sting
• CTA on screen as lower-third text
• Brand: ${METADATA.brand}
• Website CTA: ${METADATA.website}
==========================================================
`.trim();

return [
  {
    json: {
      // Context
      production_date: productionDate,
      week_key: weekKey,
      day_key: dayKey,
      // Script
      format_key: script.format,
      format_label: format.label,
      title: script.title,
      hook: script.hook,
      body: script.body,
      cta: script.cta,
      full_script_text: fullScriptText,
      // YouTube
      youtube_title: script.youtube_title,
      youtube_description: script.youtube_description,
      youtube_tags: script.youtube_tags,
      youtube_tags_string: script.youtube_tags.join(", "),
      // Stock footage
      pexels_search_query: format.pexels_keywords[0],
      pexels_keywords: format.pexels_keywords,
      // Brief
      production_brief: productionBrief,
      // Brand
      brand: METADATA.brand,
      website: METADATA.website,
      contact_email: METADATA.email,
      video_format: METADATA.video_format,
      voice_tone: METADATA.voice_tone
    }
  }
];

// Receive script data from Select Script node (input[0])
// and Pexels results from the HTTP node (input[1]).
// Merge into a single enriched object.

const scriptData = $('Select Script for Today').first().json;
const pexelsResponse = $('Search Pexels for B-Roll').first().json;

const videos = (pexelsResponse.videos || []).slice(0, 5).map(v => ({
  id: v.id,
  url: v.url,
  duration: v.duration,
  image_preview: v.image,
  download_link: (v.video_files || []).find(f => f.quality === 'hd')?.link
    || (v.video_files || [])[0]?.link
    || null,
  photographer: v.user?.name || 'Unknown'
}));

return [
  {
    json: {
      ...scriptData,
      broll_videos: videos,
      broll_count: videos.length,
      broll_primary_url: videos[0]?.download_link || null
    }
  }
];
